#!/bin/bash
# Copy custom_Dataset images into LMGaussian's expected layout.
# LMGaussian expects: data/<scene>/train/images/
# DUSt3R init, Marigold depth/normal are generated by subsequent steps.
#
# Usage: bash setup_custom_dataset.sh

SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
SRC_DIR="/workspace/custom_Dataset/inputs"
DST_DIR="${SCRIPT_DIR}/data/custom_29/train/images"

mkdir -p "${DST_DIR}"

# Copy all 29 input images
for i in $(seq 0 28); do
    cp "${SRC_DIR}/rgb_${i}.png" "${DST_DIR}/rgb_${i}.png"
done

echo "Copied 29 images to ${DST_DIR}"
echo "Contents:"
ls -la "${DST_DIR}/"
echo ""
echo "Next steps:"
echo "  1. python dust3r/coarse_initialization.py -s data/custom_29"
echo "  2. python Marigold/getmonodepthnormal.py -s data/custom_29"
echo "  3. python stage1_360.py -s data/custom_29 -r 2 --save outputs/custom_29"
